#!/bin/bash
# Stáhne Canva thumbnaily do assets/canva/
# Spusť: bash ~/Projects/www-nelldesign/assets/download-canva.sh

DIR="$(dirname "$0")/canva"
mkdir -p "$DIR"

dl() {
  local name="$1" url="$2"
  local out="$DIR/${name}.jpg"
  local status
  status=$(curl -sL -o "$out" -w "%{http_code}" "$url")
  local size
  size=$(stat -f%z "$out" 2>/dev/null || echo 0)
  if [ "$status" = "200" ] && [ "$size" -gt 1000 ]; then
    echo "✓ $name"
  else
    echo "✗ $name (HTTP $status)"
  fi
}

echo "Stahuji 21 obrázků do $DIR ..."

